files.file:
import numpy as np from pathlib import Path
# НАЛАШТУВАННЯ VARIANT = 5 SEED = 42 N, M = 400, 4 DIST = "normal"
def generate_data(n, m, dist, seed=42): rng = np.random.default_rng(seed) if dist == "normal": return rng.normal(loc=0.0, scale=1.0, size=(n, m)) elif dist == "uniform": return rng.uniform(low=0.0, high=1.0, size=(n, m)) return None
def minmax_normalize(X, eps=1e-12): x_min = X.min(axis=0) x_max = X.max(axis=0) return (X - x_min) / (x_max - x_min + eps)
def zscore_standardize(X, eps=1e-12): mu = X.mean(axis=0) sigma = X.std(axis=0) return (X - mu) / (sigma + eps)
def main(): print(f"--- Lab 2: Variant {VARIANT} (NumPy) ---") X = generate_data(N, M, DIST, seed=SEED)
# 1. Base Stats print(f"X shape: {X.shape}, dtype: {X.dtype}") print(f"Mean per col: {np.round(X.mean(axis=0), 3)}")
# 2. Variant Operation (Correlation Matrix) corr_matrix = np.corrcoef(X, rowvar=False)
# 3. Norm/Std X_norm = minmax_normalize(X) X_std = zscore_standardize(X)
# Save results np.save(f"X_variant{VARIANT:02d}.npy", X)
# Text Report lines = [ f"Lab 2 Report (Variant {VARIANT})", f"Shape: {X.shape}", "", "Correlation Matrix (Top-left 4x4):", str(np.round(corr_matrix, 4)), "", "Normalization Check (Min/Max of X_norm columns):", f"Min: {np.round(X_norm.min(axis=0), 2)}", f"Max: {np.round(X_norm.max(axis=0), 2)}" ]
report_text = "\n".join(lines) Path(f"report_variant{VARIANT:02d}.txt").write_text(report_text, encoding="utf-8") print(report_text)
if __name__ == "__main__": main()

